async (params, browser) => {
  // Open Wayback Machine search
  await browser.open(`https://web.archive.org/web/*/${params.query}`)

  // Wait for results
  await browser.waitForSelector('#wb-calendar, .calendar-grid, .calendar, [class*="CalendarMonth"], .content', 15000)

  // Let results render
  await browser.wait(2500)

  // Extract results
  const search_results = await browser.evaluate(`const snapshots = document.querySelector('#wb-calendar, .calendar-grid, .calendar, [class*="CalendarMonth"]')?.textContent?.trim()?.slice(0, 500) || ''; const sparkline = document.querySelector('.sparkline-container, [class*="captures"], [class*="capture-count"], .captures-range-info')?.textContent?.trim() || ''; return { url_searched: '' + params.query + '', calendar_summary: snapshots, captures_info: sparkline, page_url: window.location.href };`)

  return search_results
}
